from flask import Flask, send_from_directory, abort, request
from werkzeug.utils import secure_filename

app = Flask(__name__)
UPLOAD_FOLDER = 'uploads'
app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

# Ensure upload directory exists
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

# Legacy file mapping for backward compatibility
LEGACY_MAPPING = {
    'old_file1.txt': 'new_file1.txt',
    'old_file2.pdf': 'new_file2.pdf',
    # Add more legacy mappings as needed
}

def is_safe_path(base_path, path):
    """Check if path is safe to access"""
    try:
        abs_base = os.path.abspath(base_path)
        abs_path = os.path.abspath(os.path.join(base_path, path))
        return abs_path.startswith(abs_base)
    except Exception:
        return False

def get_legacy_filename(filename):
    """Get legacy filename if it exists in mapping"""
    return LEGACY_MAPPING.get(filename, filename)

@app.route('/uploads/<path:filename>')
def legacy_static_files(filename):
    """Serve static files from uploads directory with legacy support"""
    # Secure the filename
    safe_filename = secure_filename(filename)
    
    # Check if it's a legacy filename and get the actual file
    actual_filename = get_legacy_filename(safe_filename)
    
    # Build full path
    full_path = os.path.join(app.config['UPLOAD_FOLDER'], actual_filename)
    
    # Security check
    if not is_safe_path(app.config['UPLOAD_FOLDER'], actual_filename):
        abort(404)
    
    # Check if file exists
    if not os.path.exists(full_path):
        # Try with legacy filename
        legacy_path = os.path.join(app.config['UPLOAD_FOLDER'], safe_filename)
        if not os.path.exists(legacy_path):
            abort(404)
        full_path = legacy_path
    
    # Verify file is within upload directory
    if not os.path.abspath(full_path).startswith(os.path.abspath(app.config['UPLOAD_FOLDER'])):
        abort(404)
    
    try:
        return send_from_directory(app.config['UPLOAD_FOLDER'], actual_filename, as_attachment=False)
    except Exception:
        abort(404)

